def max_Prime_Factors(n):
    if n <= 1:
        return 1
    largest_prime = 1
    # Check for 2
    if n % 2 == 0:
        largest_prime = 2
        while n % 2 == 0:
            n = n // 2
    # Check for odd numbers starting from 3
    i = 3
    while i * i <= n:
        while n % i == 0:
            largest_prime = i
            n = n // i
        i += 2
    # If remaining n is a prime
    if n > 1:
        largest_prime = n
    return largest_prime

assert max_Prime_Factors(15) == 5
assert max_Prime_Factors(6) == 3
assert max_Prime_Factors(2) == 2
